const body = $input.first().json.body;
const messageType = Object.keys(body.data.message || {})[0];
if (!messageType || messageType === 'protocolMessage' || messageType === 'reactionMessage') { return []; }
const remoteJid = body.data.key.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '').replace('@lid', '');
const instance = body.instance || 'teste';
const messageId = body.data.key.id || '';
const isAudio = !!(body.data.message?.audioMessage || body.data.message?.pttMessage);
const message = body.data.message?.conversation || body.data.message?.extendedTextMessage?.text || '';
return [{ json: { phone, message, instance, messageId, isAudio } }];

const phone = $('Extrai texto').first().json.phone;
const message = $('Extrai texto').first().json.message;
const messageId = $('Extrai texto').first().json.messageId || '';
if (!message || message.trim() === '') { return []; }
let historico = [];
let lastMessage = '';
let lastMessageAt = null;
let lastMessageId = '';
try {
  const rows = $('Busca histórico').all();
  if (rows.length > 0 && rows[0].json.historico) {
    historico = JSON.parse(rows[0].json.historico);
    lastMessage = rows[0].json.last_message || '';
    lastMessageAt = rows[0].json.last_message_at ? new Date(rows[0].json.last_message_at) : null;
    lastMessageId = rows[0].json.last_message_id || '';
  }
} catch(e) { historico = []; }
if (messageId && messageId === lastMessageId) { return []; }
const agora = new Date();
const diff = lastMessageAt ? (agora - lastMessageAt) / 1000 : 999;
if (message === lastMessage && diff < 30) { return []; }
historico = historico.filter(m => m.content && m.content.trim() !== '');
historico.push({ role: 'user', content: message });
return [{ json: { phone, message, messageId, historico } }];

const resposta = $input.first().json.content[0].text;
const phone = $('Monta contexto').first().json.phone;
const message = $('Monta contexto').first().json.message;
const messageId = $('Monta contexto').first().json.messageId;
const historico = $('Monta contexto').first().json.historico;
historico.push({ role: 'assistant', content: resposta });
return [{ json: { resposta, phone, message, messageId, historico } }];

const resposta = $('Extrai resposta').first().json.resposta;
const phone = $('Extrai resposta').first().json.phone;
const triagem = resposta.replace('[TRIAGEM_COMPLETA]', '').trim();
const texto = '🐾 Nova triagem pela MIA:\n\n' + triagem + '\n\nTelefone tutor: ' + phone;
return [{ json: { texto, phone } }];

